            if (firstCategory != null) {
                DebugLogger.log("AUTO", "Starting auto-play for category: $firstCategory")
                playType(firstCategory)
            }
        }
    }

    autoPlayHandler.postDelayed(autoPlayRunnable!!, 60000) // 1 minute delay
}

