<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0, user-scalable=no, viewport-fit=cover">
    <title>Conduit IDE v7.0 (Healer Test)</title>

    <!-- LIBRARIES -->
    <script src="https://cdnjs.cloudflare.com/ajax/libs/acorn/8.11.3/acorn.min.js"></script>
    <script src="https://unpkg.com/@babel/standalone/babel.min.js"></script>

    <script src="https://cdnjs.cloudflare.com/ajax/libs/ace/1.32.7/ace.js"></script>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js"></script>
    <script src="https://cdn.jsdelivr.net/npm/ace-diff@2.1.0/dist/ace-diff.min.js"></script>
    <link href="https://cdn.jsdelivr.net/npm/ace-diff@2.1.0/dist/ace-diff.min.css" rel="stylesheet">
    <script src="https://cdn.jsdelivr.net/npm/marked/marked.min.js"></script>
    <script src="https://cdn.jsdelivr.net/npm/eruda"></script>
    <script>eruda.init();</script>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500&display=swap" rel="stylesheet">

    <style>
        .model-item {
            display: flex; align-items: center; justify-content: space-between;
            padding: 12px; border-bottom: 1px solid var(--border); transition: background 0.2s;
        }
        .model-item:hover { background: #1a1a1c; }
        .model-item .model-id { font-family: 'JetBrains Mono'; font-size: 12px; color: #eee; flex: 1; }
        .model-item .model-actions { display: flex; gap: 8px; }

        :root {
            --bg: #050505;
            --card-bg: #151517;
            --input-bg: #0a0a0a;
            --primary: #3b82f6;
            --primary-dim: rgba(59, 130, 246, 0.1);
            --ai-accent: #d946ef;
            --dev: #eab308;
            --prod: #22c55e;
            --danger: #ef4444;
            --text-main: #ffffff;
            --text-muted: #a1a1aa;
            --border: #27272a;
            --nav-height: 80px;
        }

        * { box-sizing: border-box; -webkit-tap-highlight-color: transparent; }

        body {
            margin: 0; padding: 0; height: 100vh;
            background-color: var(--bg); color: var(--text-main);
            font-family: 'Inter', sans-serif;
            display: flex; flex-direction: column;
            overflow: hidden;
        }

        .hidden { display: none !important; }
        .flex-between { display: flex; justify-content: space-between; align-items: center; }
        .flex-gap { display: flex; gap: 8px; }

        /* MAIN VIEW LAYOUT */
        .main-view {
            flex: 1; overflow-y: auto; padding: 20px;
            padding-bottom: calc(var(--nav-height) + 40px);
            scrollbar-width: none;
            scroll-behavior: smooth;
        }
        /* Safe space for the very bottom of any tab */
        .bottom-spacer {
            height: var(--nav-height);
            width: 100%;
            flex-shrink: 0;
        }
        .main-view::-webkit-scrollbar { display: none; }

        .tab-content { display: none; animation: fadeUp 0.2s ease-out; }
        .tab-content.active { display: block; }
        @keyframes fadeUp { from { opacity: 0; transform: translateY(5px); } to { opacity: 1; transform: translateY(0); } }

        .header { font-size: 24px; font-weight: 700; margin-bottom: 20px; display: flex; align-items: center; justify-content: space-between; flex-shrink: 0; }

        .card {
            background: var(--card-bg); border: 1px solid var(--border);
            border-radius: 16px; padding: 16px; margin-bottom: 16px;
        }

        /* BUTTONS */
        .btn {
            width: 100%; padding: 14px; border-radius: 12px; border: none;
            font-weight: 600; font-size: 15px; cursor: pointer;
            display: flex; align-items: center; justify-content: center; gap: 8px;
            color: white; transition: opacity 0.2s;
        }
        .btn:active { opacity: 0.7; }
        .btn-primary { background: var(--primary); }
        .btn-dev { background: var(--dev); color: black; }
        .btn-prod { background: var(--prod); }
        .btn-danger { background: var(--danger); }
        .btn-outline { background: transparent; border: 1px solid var(--border); color: var(--text-muted); }

        /* INPUTS */
        .input-group { margin-bottom: 16px; }
        .input-label { display: block; color: var(--text-muted); font-size: 11px; margin-bottom: 6px; text-transform: uppercase; letter-spacing: 0.5px; }
        .input-field {
            width: 100%; background: var(--input-bg); border: 1px solid var(--border);
            color: var(--text-main); padding: 12px; border-radius: 10px;
            font-family: 'JetBrains Mono', monospace; font-size: 13px;
        }
        .input-field:focus { outline: 2px solid var(--primary); border-color: transparent; }

        /* FILE LIST */
        .file-list { display: flex; flex-direction: column; gap: 0; }
        .file-item {
            display: flex; justify-content: space-between; align-items: center;
            padding: 12px; border-bottom: 1px solid var(--border);
        }
        .file-item:last-child { border-bottom: none; }

        /* VERSIONS / HISTORY */
        .version-item { position: relative; padding: 12px 0; border-bottom: 1px solid var(--border); }
