        }
        iframe { width: 100%; height: 100%; border: none; }

        /* FULLSCREEN PREVIEW MODE */
        body.fs-mode .nav-bar, body.fs-mode .header, body.fs-mode .main-view > p, body.fs-mode .fs-hide { display: none !important; }
