        /* EF MANAGER RESPONSIVE OVERRIDES */
        .ef-layout { display: flex; flex: 1; overflow: hidden; }
        .ef-sidebar { width: 220px; border-right: 1px solid var(--border); display: flex; flex-direction: column; background: #0a0a0a; flex-shrink: 0; }
        .ef-list { flex: 1; overflow-y: auto; padding: 8px; display: flex; flex-direction: column; gap: 4px; }

        @media (max-width: 768px) {
            .ef-layout { flex-direction: column; }
