        .code-copy { position: absolute; top: 22px; right: 8px; background: rgba(255,255,255,0.1); border: none; color: #fff; padding: 2px 6px; border-radius: 4px; font-size: 10px; cursor: pointer; }
        .diff-remove { background: rgba(239, 68, 68, 0.1); border-left: 2px solid var(--danger); color: #fca5a5; }
        .diff-add { background: rgba(34, 197, 94, 0.1); border-left: 2px solid var(--prod); color: #86efac; }

        /* Custom Diff Markers */
        /* Enhanced Ace Diff Markers */
        .marker-remove { position: absolute; background: rgba(239, 68, 68, 0.25); border-left: 3px solid var(--danger); z-index: 20; }
        .marker-add { position: absolute; background: rgba(34, 197, 94, 0.25); border-left: 3px solid var(--prod); z-index: 20; }

        /* ============================ */
        /*      NEW AI CHAT STYLES      */
        /* ============================ */

        /* Multi-Action FAB Group */
        .fab-group {
            position: fixed; bottom: 100px; right: 20px; z-index: 200;
            display: flex; flex-direction: column; align-items: center; gap: 15px;
        }
        .fab-main {
            width: 56px; height: 56px; border-radius: 50%;
