    async function toggleChatHistory() {
        const list = document.getElementById('chat-history-list');
        if (list.classList.contains('active')) {
            list.classList.remove('active');
            return;
        }

        list.classList.add('active');
        list.innerHTML = '<div style="text-align:center; padding:20px; color:#666;">Fetching history...</div>';

        try {
            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: apiBody({ action: 'fetch_chats' })
            });
            const data = await res.json();

            if (!data.chats || data.chats.length === 0) {
                list.innerHTML = '<div style="text-align:center; padding:20px; color:#666;">No past conversations.</div>';
                return;
            }

            list.innerHTML = data.chats.map(chat => `
                <div class="history-item" onclick="loadChatSession('${chat.id}')">
                    <div class="history-title">${chat.title}</div>
                    <div class="history-date">${new Date(chat.created_at).toLocaleDateString()}</div>
                </div>
