    async function loadChatSession(id) {
        document.getElementById('chat-history-list').classList.remove('active');
        currentChatId = id;
        document.getElementById('chat-messages').innerHTML = '<div style="text-align:center; padding:20px; color:#666;">Restoring chat...</div>';

        try {
            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: apiBody({ action: 'load_chat', chat_id: id })
            });
            const data = await res.json();

            chatHistory = data.messages || [];
            const container = document.getElementById('chat-messages');
            container.innerHTML = '';

            renderChatFromHistory();
            container.scrollTop = container.scrollHeight;

        } catch (e) {
            alert("Failed to load chat: " + e.message);
        }
    }

