<script>
  // --- CONFIG & STATE ---
    let CONFIG = { 
        funcUrl: localStorage.getItem('conduit_funcUrl') || '',
        repoName: localStorage.getItem('conduit_repoName') || 'IDE',
        projectPath: localStorage.getItem('conduit_projectPath') || '',
