        autoSanity: localStorage.getItem('conduit_auto_sanity') === 'true',
        showPreview: localStorage.getItem('conduit_showPreview') !== 'false', // Default to true
        efDeploymentMode: localStorage.getItem('conduit_ef_mode') || 'default',
        wasmValidation: localStorage.getItem('conduit_wasm_validation') !== 'false'
    };

    // Global State
    let sessionLogs = [];
    let dbHistory = [];
    let repoFiles = []; 
    let editHistory = []; 
    let historyIndex = -1;
    let chatHistory = []; 
    let logOffset = 0;
    let historyOffset = 0;
    let workflowPage = 1;

    // --- AI CONFIG STATE ---
    const DEFAULT_AI_CONFIG = {
      providers: {
        'default_main': {
          name: 'DeepSeek V3 (OpenRouter)',
          baseUrl: 'https://openrouter.ai/api/v1/chat/completions',
          model: 'deepseek/deepseek-chat', 
          apiKeyEnv: 'Deepseek_API',
          type: 'openai'
        },
        'default_groq': {
          name: 'GroqCloud',
          baseUrl: 'https://api.groq.com/openai/v1/chat/completions',
          model: 'openai/gpt-oss-120b',
          apiKeyEnv: 'GROQ_API_KEY',
          type: 'openai'
        },
        'default_analyst': {
           name: 'Gemini Flash (Google)',
           baseUrl: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-flash-lite-latest:generateContent',
           model: '',
           apiKeyEnv: 'GEMINI_API_KEY',
           type: 'google'
        }
      },
      roles: {
        chat: 'default_groq',
        architect: 'default_groq',
        fast_fix: 'default_groq',
        analyst: 'default_analyst'
      }
    };

    // Load from local storage or fallback to default
    window.aiConfig = JSON.parse(localStorage.getItem('conduit_ai_config') || 'null') || DEFAULT_AI_CONFIG;

    // Caches
    window.OP_CACHE = {}; 
    window.BUILD_CACHE = {}; 
    let FILE_OP_MAP = {}; 
