    // --- AI CHAT LOGIC ---
    function toggleChat(show) {
        document.getElementById('chat-overlay').classList.toggle('active', show);
        if(show) document.getElementById('chat-input').focus();
    }

    async function sendChat() {
        const input = document.getElementById('chat-input');
        const msg = input.value.trim();
        if(!msg) return;

        input.value = '';
        chatHistory.push({ role: 'user', text: msg });
        renderChatFromHistory();
        await processAIResponse();
    }

    async function processAIResponse() {
        const loadingId = addChatMessage('ai', 'Thinking...', true);
        const contextPayload = [];

        try {
            // --- SURGICAL DEBUG OVERRIDE ---
            if (window.SURGICAL_DEBUG_DATA) {
                contextPayload.push({
                    path: window.SURGICAL_DEBUG_DATA.path,
                    content: b64EncodeUnicode(window.SURGICAL_DEBUG_DATA.content)
                });
                // Clear after use to prevent polluting next chat
                window.SURGICAL_DEBUG_DATA = null;
                console.log("[AI] Using Surgical Context (Single File)");
            } else {
                // Standard: Grab all checked files
                const checkedBoxes = document.querySelectorAll('#file-list-container .file-check:checked');
                const filePaths = Array.from(checkedBoxes).map(cb => cb.value);
                for (const path of filePaths) {
                    if (window.CURRENT_FILE_CACHE && window.CURRENT_FILE_CACHE[path]) {
                        contextPayload.push({ path: path, content: b64EncodeUnicode(window.CURRENT_FILE_CACHE[path].content) });
                    } else {
                        const res = await fetch(CONFIG.funcUrl, { method: 'POST', headers: {'Content-Type': 'application/json'}, body: apiBody({ action: 'preview_file', file_path: path }) });
                        const data = await res.json();
                        contextPayload.push({ path: path, content: data.content });
                    }
                }
                console.log(`[AI] Using Global Context (${contextPayload.length} files)`);
            }

            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: apiBody({ action: 'ai_chat', messages: chatHistory, context_files: contextPayload })
            });
            const data = await res.json();

            // Remove loading bubble (it's not in chatHistory yet)
            const loadingEl = document.getElementById(loadingId);
            if (loadingEl && loadingEl.parentElement) loadingEl.parentElement.remove();

            let replyText = data.reply || "No response";
            chatHistory.push({ role: 'model', text: replyText });

            // Re-render to show the new message with proper actions
            renderChatFromHistory();

            // Handle JSON artifacts
            const jsonMatch = replyText.match(/```json\s*([\s\S]*?)\s*```/) || replyText.match(/\[\s*\{[\s\S]*\}\s*\]/);
            if (jsonMatch) {
                const jsonStr = jsonMatch[1] || jsonMatch[0];
                try {
                    JSON.parse(jsonStr); 
                    document.getElementById('json-input').value = jsonStr;
                    saveState();
                    const patcherTabBtn = document.querySelectorAll('.nav-item')[1];
                    patcherTabBtn.style.color = "#d946ef";
                    setTimeout(() => patcherTabBtn.style.color = "", 2000);
                } catch(e) { console.error("Bad JSON", e); }
            }

            saveCurrentChat();

        } catch (e) {
            document.getElementById(loadingId).innerText = "Error: " + e.message;
        }
    }

    function renderChatFromHistory() {
        const container = document.getElementById('chat-messages');
        container.innerHTML = '';
        chatHistory.forEach((msg, index) => {
            // Pass index to link actions
            addChatMessage(msg.role === 'model' ? 'ai' : msg.role, msg.text, false, index);
        });
        container.scrollTop = container.scrollHeight;
    }

    async function retryChat() {
        // Remove last AI message if exists
        if (chatHistory.length > 0 && chatHistory[chatHistory.length - 1].role === 'model') {
            chatHistory.pop();
        }
        renderChatFromHistory();
        await processAIResponse();
    }

    function editUserMsg(index) {
        const msg = chatHistory[index];
        if (!msg) return;

        // Populate input
        document.getElementById('chat-input').value = msg.text;
        document.getElementById('chat-input').focus();

        // Truncate history to BEFORE this message
        chatHistory = chatHistory.slice(0, index);
        renderChatFromHistory();
    }

