    async function downloadJobLogs(jobId, jobName) {
        try {
            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: apiBody({
                    action: 'fetch_job_logs',
                    job_id: jobId
                })
            });
            const data = await res.json();
            const blob = new Blob([data.logs || ""], {
                type: 'text/plain'
            });
            const link = document.createElement('a');
            link.href = URL.createObjectURL(blob);
            link.download = `${jobName}.log`;
