                </div>
            </div>
            <input type="text" class="input-field" placeholder="Fuzzy search files..." style="margin-bottom: 12px;" onkeyup="filterFiles(this.value)">
            <div class="card" style="padding: 0; overflow: hidden;">
                <div id="file-list-container" class="file-list">
