<script>
  // --- CONFIG & STATE ---
    let CONFIG = { 
        funcUrl: localStorage.getItem('conduit_funcUrl') || '',
        repoName: localStorage.getItem('conduit_repoName') || 'IDE',
        projectPath: localStorage.getItem('conduit_projectPath') || '',
        autoFix: localStorage.getItem('conduit_auto_fix') === 'true',
        autoSanity: localStorage.getItem('conduit_auto_sanity') === 'true',
        showPreview: localStorage.getItem('conduit_showPreview') !== 'false', // Default to true
        efDeploymentMode: localStorage.getItem('conduit_ef_mode') || 'default',
        wasmValidation: localStorage.getItem('conduit_wasm_validation') !== 'false'
    };

    // Global State
    let sessionLogs = [];
    let dbHistory = [];
    let repoFiles = []; 
    let editHistory = []; 
    let historyIndex = -1;
    let chatHistory = []; 
    let logOffset = 0;
    let historyOffset = 0;
    let workflowPage = 1;

    // --- AI CONFIG STATE ---
    const DEFAULT_AI_CONFIG = {
      providers: {
        'default_main': {
          name: 'DeepSeek V3 (OpenRouter)',
          baseUrl: 'https://openrouter.ai/api/v1/chat/completions',
          model: 'deepseek/deepseek-chat', 
          apiKeyEnv: 'Deepseek_API',
          type: 'openai'
        },
        'default_groq': {
          name: 'GroqCloud',
          baseUrl: 'https://api.groq.com/openai/v1/chat/completions',
          model: 'openai/gpt-oss-120b',
          apiKeyEnv: 'GROQ_API_KEY',
          type: 'openai'
        },
        'default_analyst': {
           name: 'Gemini Flash (Google)',
           baseUrl: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-flash-lite-latest:generateContent',
           model: '',
           apiKeyEnv: 'GEMINI_API_KEY',
           type: 'google'
        }
      },
      roles: {
        chat: 'default_groq',
        architect: 'default_groq',
        fast_fix: 'default_groq',
        analyst: 'default_analyst'
      }
    };

    // Load from local storage or fallback to default
    window.aiConfig = JSON.parse(localStorage.getItem('conduit_ai_config') || 'null') || DEFAULT_AI_CONFIG;

    // Caches
    window.OP_CACHE = {}; 
    window.BUILD_CACHE = {}; 
    let FILE_OP_MAP = {}; 
    let aceEditorInstance = null;
    let diffLeft = null;
    let diffRight = null;

    // --- INIT ---
    window.onload = async () => {
        if (window.IS_CONDUIT_PREVIEW) return; // Recursion Guard

        // Load Settings into UI
        document.getElementById('setting-func-url').value = CONFIG.funcUrl;
        document.getElementById('setting-repo-name').value = CONFIG.repoName;
        document.getElementById('setting-project-path').value = CONFIG.projectPath;
        document.getElementById('setting-auto-fix').checked = CONFIG.autoFix;
        document.getElementById('setting-auto-sanity').checked = CONFIG.autoSanity;
        document.getElementById('setting-show-preview').checked = CONFIG.showPreview;
        document.getElementById('setting-wasm-validation').checked = CONFIG.wasmValidation;
        document.getElementById('setting-ef-mode').value = CONFIG.efDeploymentMode;

        renderAIConfigUI(); // Render AI Settings
        applyPreviewTabVisibility(); // Apply visibility on load

        // Restore Editor State
        const savedJson = localStorage.getItem('conduit_autosave');
        if(savedJson) {
            document.getElementById('json-input').value = savedJson;
            editHistory.push(savedJson);
            historyIndex = 0;
        }

        if(typeof acorn === 'undefined') console.warn("Acorn missing. Syntax checking disabled.");

        // Listen for console sync from preview iframe
        window.addEventListener('message', (e) => {
            if (e.data && e.data.type === 'CONDUIT_CONSOLE') {
                // Avoid spam: check if last log was the same
                const lastLog = document.querySelector('.runtime-log');
                if (lastLog && lastLog.dataset.msg === e.data.msg) {
                    const countBadge = lastLog.querySelector('.log-count') || document.createElement('span');
                    if (!lastLog.querySelector('.log-count')) {
                        countBadge.className = 'log-count';
                        countBadge.style.cssText = 'background:#444; color:#fff; padding:2px 6px; border-radius:10px; font-size:9px; margin-left:8px;';
                        lastLog.querySelector('.log-meta').appendChild(countBadge);
                    }
                    lastLog.dataset.count = parseInt(lastLog.dataset.count || 1) + 1;
                    countBadge.innerText = `x${lastLog.dataset.count}`;
                    return;
                }

                const logId = addTerminalCard(null, {});
                const color = e.data.method === 'error' ? 'var(--danger)' : (e.data.method === 'warn' ? 'var(--dev)' : 'var(--primary)');
                const el = document.getElementById(logId);
                if (!el) return;

                el.classList.add('runtime-log');
                el.dataset.msg = e.data.msg;
                el.innerHTML = '<div class="log-header expanded" style="border-left-color:' + color + ';">' +
                    '<div class="log-meta">' +
                    '<span class="status-pill" style="background:' + color + '; color:white;">RUNTIME</span>' +
                    '<span style="font-size:11px; color:#fff; white-space:nowrap; overflow:hidden; text-overflow:ellipsis; max-width:200px;">' + escapeHtml(e.data.msg) + '</span>' +
                    '</div>' +
                    '<button class="btn-dev" style="width:auto; padding:4px 8px; font-size:10px; color:black;" onclick="fixPreviewError(\'' + escapeHtml(e.data.msg).replace(/'/g, "\\'") + '\')">✨ Fix</button>' +
                    '</div>';

                // Self-destruct after 60 seconds to keep terminal clean
                setTimeout(() => { if(el.parentElement) el.remove(); }, 60000);
            }
        });

        if(CONFIG.funcUrl) {
            await fetchState();
            setTimeout(() => bundleAndPreview(null), 500); 
        } else {
            switchTab('tab-settings', document.querySelectorAll('.nav-item')[5]);
        }
    };

    // --- CORE UTILS ---
    /**
     * Tries to parse JSON. If it fails due to bad escaping (common with AI),
     * it attempts to double-escape backslashes that aren't valid JSON control chars.
     */
    function smartJSONParse(jsonString) {
        try {
            return JSON.parse(jsonString);
        } catch (e) {
            console.warn("Standard JSON parse failed, attempting Robust Auto-Fix...");
            let fixed = jsonString
                // 1. Fix backslashes that aren't part of a valid escape sequence
                .replace(/\\(?!["\\/bfnrtu])/g, "\\\\")
                // 2. Fix literal newlines inside strings (replace with \n)
                .replace(/(\n)/g, (match, p1, offset) => {
                    // Only replace if we are likely inside a quoted string
                    const before = jsonString.slice(0, offset);
                    const quoteCount = (before.match(/"/g) || []).length;
                    return (quoteCount % 2 === 1) ? "\\n" : "\n";
                });

            try {
                const cleanObj = JSON.parse(fixed);
                document.getElementById('json-input').value = fixed;
                if (typeof saveState === 'function') saveState();
                showGlobalToast("✨ Robust Auto-Correction Applied");
                return cleanObj;
            } catch (e2) {
                console.error("Robust fix failed:", e2);
                throw e; // Throw original error for better debugging
            }
        }
    }

    function b64DecodeUnicode(str) {
        return decodeURIComponent(atob(str).split('').map(function(c) {
            return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
        }).join(''));
    }

    // Unicode-Safe Encoder for AI Context
    function b64EncodeUnicode(str) {
        return btoa(encodeURIComponent(str).replace(/%([0-9A-F]{2})/g,
            function toSolidBytes(match, p1) { return String.fromCharCode('0x' + p1); }));
    }

    function apiBody(obj) {
        // INJECT AI CONFIG INTO EVERY REQUEST
        return JSON.stringify({ ...obj, repo_name: CONFIG.repoName, ai_config: window.aiConfig });
    }

    function resolvePath(base, relative) {
        const stack = base.split('/');
        stack.pop(); 
        const parts = relative.split('/');
        for (let i = 0; i < parts.length; i++) {
            if (parts[i] === '.') continue;
            if (parts[i] === '..') stack.pop();
            else stack.push(parts[i]);
        }
        return stack.join('/');
    }

    // Acorn is deprecated. Syntax checking is now handled by backend WASM.
