    function updateTerminalCard(id, response, originalPayload, isLive = false) {
        const el = document.getElementById(id);
        if(!el) return;

        // Define patchTitle for favorites and UI display
        let patchTitle = "Patch Operation";
        if (Array.isArray(originalPayload)) {
            const commentOp = originalPayload.find(p => p.action === 'comment');
            if (commentOp && commentOp.text) {
                patchTitle = commentOp.text.split('\n')[0].substring(0, 60);
            } else {
                const opCount = originalPayload.filter(p => p.action !== 'comment').length;
                patchTitle = `Patch: ${opCount} operations`;
            }
        }

        // Ensure we capture the SHA if present
        if (response && response.commit_sha) {
            el.dataset.commitSha = response.commit_sha;
        }

        if(response.error) {
            el.innerHTML = `<div class="log-header" style="color:var(--danger)"><span>API Error</span><span class="status-pill pill-fail">500</span></div><div class="log-body open" style="padding:12px; color:var(--danger); font-size:11px; overflow-wrap:anywhere;">${escapeHtml(response.error)}</div>`;
            return;
        }

        let failCount = 0; 
        let hasAI = false;
        // Check if the source payload was an Auto-Fix
        if (Array.isArray(originalPayload) && originalPayload.some(p => p.action === 'comment' && p.text && p.text.includes('[Auto-Fix]'))) {
            hasAI = true;
        }
        let opHtml = '';

        if(response.results && Array.isArray(response.results)) {
            if (response.results.length === 0) {
                 // FIX: explicit message when no operations were performed
                 opHtml = `<div class="op-row"><div class="op-details" style="color:#666; font-style:italic; padding:12px;">No files were modified. (Check file_path and action parameters)</div></div>`;
            } else {
                response.results.forEach(fileRes => {
                    opHtml += `<div style="background:#111; padding:6px 12px; font-weight:bold; color:#fff; border-bottom:1px solid #222; display:flex; justify-content:space-between;"><span>📄 ${escapeHtml(fileRes.file)}</span><span style="opacity:0.5; font-size:10px">${escapeHtml(fileRes.status)}</span></div>`;
                    if(fileRes.operations) {
                        fileRes.operations.forEach(op => {
                            if(!op.success) failCount++;
                            const isFail = !op.success;
                            const opId = 'op-' + Math.random().toString(36).substr(2, 9);

                            if(isLive && fileRes.file) {
                                if (!FILE_OP_MAP[fileRes.file]) FILE_OP_MAP[fileRes.file] = [];
                                FILE_OP_MAP[fileRes.file].push({ id: opId, type: op.type, replace_with: op.replace_with, content: op.content, start_line: op.start_line, end_line: op.end_line });
                            }

                            window.OP_CACHE[opId] = { file: fileRes.file, op: op, commit_sha: response.commit_sha || null };

                            let scoreColor = 'var(--text-muted)';
                            let badgeText = `${op.score || 0}% Match`;
                            if (op.message && (op.message.includes('AI') || op.is_ai_fix)) { 
                                scoreColor = '#d946ef'; 
                                const strategy = op.ai_strategy === 'range_replace' ? `L${op.start_line}-${op.end_line}` : `L${op.anchor_line}`;
                                badgeText = `✨ AI ${strategy} (${op.score || 0}%)`; 
                                hasAI = true; 
                            } 
                            else if(op.score === 100) scoreColor = 'var(--prod)';
                            else if(op.score >= 80) scoreColor = 'var(--dev)';
                            else if(op.score > 0) scoreColor = 'var(--danger)';

                            opHtml += `
                            <div class="op-row ${isFail ? 'row-fail' : ''}" onclick="toggleOpMenu('${opId}')">
                                <div class="op-title">
                                    <span>${escapeHtml(op.type.replace(/_/g, ' ').toUpperCase())}</span>
                                    <span class="score-badge" style="border:1px solid ${scoreColor}; color:${scoreColor}">${escapeHtml(badgeText)}</span>
                                </div>
                                <div class="op-details">${escapeHtml(op.message)}</div>
                            </div>
                            <div id="${opId}-opts" class="op-options">
                                <button class="op-opt-btn" onclick="openOpModal('${opId}')">Details</button>
                                <button class="op-opt-btn" onclick="openDiffViewer('${opId}')">Diff</button>
                            </div>`;
                        });
                    }
                });
            }
        } else         if (response.count !== undefined) {
            opHtml = `<div class="op-row"><div class="op-details" style="color:var(--prod)">Production Deploy: ${response.count} files synced to Main.</div></div>`;
        } else if (response.stage) {
             // NEW: Render AI Trace Stage (Immediate Log)
             const stageColors = { 'INIT_AUTO_FIX': '#3b82f6', 'SURGEON_PROMPT_SENT': '#d946ef', 'SYNTAX_FIX_REQUESTED': '#eab308' };
             const color = stageColors[response.stage] || '#666';

             opHtml = `
                <div class="op-row">
                    <div class="op-title" style="color:${color}">📡 AI TRACE: ${response.stage}</div>
                    <div class="op-details" style="background:#050505; padding:8px; border-radius:6px; margin-top:5px; font-size:10px;">
                        ${response.error ? `<div style="color:var(--danger)"><b>ERROR:</b> ${escapeHtml(response.error.message)}</div>` : ''}
                        ${response.focused_content ? `<div style="color:#888; margin-top:4px;"><b>CONTEXT:</b><pre style="margin:4px 0; color:#ccc;">${escapeHtml(response.focused_content)}</pre></div>` : ''}
                        ${response.message ? `<div style="color:#aaa">${escapeHtml(response.message)}</div>` : ''}
                    </div>
                </div>`;
        } else if (response.analysis) {
             // Handle Job Analysis (The Detective)
             opHtml = `<div class="op-row"><div class="op-details" style="white-space: pre-wrap; color:#ccc; font-size:11px; line-height:1.4;">${escapeHtml(response.analysis)}</div></div>`;
        } else if (response.trigger) {
             // Handle Build Trigger Logs (The Automator)
             opHtml = `<div class="op-row"><div class="op-details" style="color:#eab308">⚡ ${escapeHtml(response.trigger)}</div></div>`;
        } else if (response.message) {
             // Handle Generic Messages (Rollbacks, etc)
             opHtml = `<div class="op-row"><div class="op-details" style="color:var(--prod)">${escapeHtml(response.message)}</div></div>`;
        }

        const isFail = failCount > 0;

        // --- UPDATED SIGNATURE LOGIC ---
        const historyEntry = response.sha ? dbHistory.find(h => h.sha === response.sha) : null;
        const conduitId = response.conduit_id || (historyEntry ? historyEntry.conduit_id : null);

        let signatureHtml = '';
        if (conduitId) {
            signatureHtml = `<span class="status-pill" style="background:var(--primary-dim); color:var(--primary); font-size:11px; padding: 2px 6px; border-radius: 4px; border:1px solid rgba(59, 130, 246, 0.2); margin-right: 8px;">#${conduitId}</span>`;
        } else if (response.sha) {
            signatureHtml = `<span class="status-pill" style="background:#222; color:#888; font-size:10px; padding: 2px 6px; border-radius: 4px; border:1px solid #333; margin-right: 8px; font-family:'JetBrains Mono', monospace;">${response.sha.substring(0,7)}</span>`;
        }

        // Store commit sha on the element for tracing
        if (response.sha) {
            el.dataset.commitSha = response.sha;
        }

        el.innerHTML = `
            <div class="log-header" onclick="toggleLogBody('${id}')">
                <div class="log-meta">
                    ${signatureHtml}
                    <button class="menu-btn favorite-btn" onclick="event.stopPropagation(); toggleFavorite('${id}', 'Patch', {title: '${patchTitle}', sha: '${response.sha || ''}'})" style="padding:0 5px; color:#555;">★</button>
                    <span class="log-time">${new Date().toLocaleTimeString()}</span>
                    ${hasAI ? '<span class="status-pill" style="background:rgba(217,70,239,0.2); color:#d946ef; margin-right:4px;">✨ AI</span>' : ''}
                    <span class="status-pill ${isFail ? 'pill-fail' : 'pill-success'}">${isFail ? `${failCount} FAILED` : 'SUCCESS'}</span>
                </div>
                <div class="flex-gap" style="position: relative;">
                    <div style="cursor:pointer; padding: 4px; display: flex; align-items: center;" onclick="toggleLogBody('${id}')">
                        <svg class="chevron" width="16" height="16" fill="none" stroke="currentColor" stroke-width="2.5" viewBox="0 0 24 24"><path d="M9 5l7 7-7 7"></path></svg>
                    </div>
                    <button class="menu-btn" style="font-size:18px; padding: 0 4px;" onclick="toggleLogMenu('${id}', event)">⋮</button>
                    <div id="${id}-menu" class="menu-dropdown">
                        <div class="menu-item" onclick="viewLogComment('${id}')">View Comment</div>
                        <div class="menu-item" onclick="viewLogData('${id}', false)">View Response JSON</div>
                                               <div class="menu-item" onclick="viewLogData('${id}', true)">View Payload JSON</div>
                        ${response.sha_before ? `<div class="menu-item" style="color:var(--dev); border-top: 1px solid #333;" onclick="undoLog('${id}', '${response.sha_before}')">Undo Patch</div>` : ''}
                        ${response.sha ? `
                            <div class="menu-item" style="border-top: 1px solid #333;" onclick="traceLogToHistory('${response.sha}')">View in History</div>
                            <div class="menu-item" onclick="traceLogToRun('${response.sha}')">View Build Log</div>
                        ` : ''}
                        <div class="menu-item danger" style="border-top: 1px solid #333;" onclick="deleteLog('${id}')">Delete Log</div>
                    </div>
                </div>
            </div>
            <div class="log-body" id="${id}-body">${opHtml}</div>
            <textarea id="${id}-response-data" class="hidden">${escapeHtml(JSON.stringify(response, null, 2))}</textarea>
