async function downloadArtifact(runId) {
        const toast = document.createElement('div');
        toast.innerHTML = `<span style="animation:pulse 1s infinite">🔍 Searching for artifact link...</span>`;
        toast.style.cssText = "position:fixed; bottom:100px; left:50%; transform:translateX(-50%); background:#333; color:white; padding:10px 20px; border-radius:30px; z-index:9999; font-size:12px;";
        document.body.appendChild(toast);

        try {
            // 1. Get the jobs for this run to find the build job
            const resJobs = await fetch(CONFIG.funcUrl, { 
                method: 'POST', 
                headers: {'Content-Type': 'application/json'}, 
                body: apiBody({ action: 'fetch_workflow_jobs', run_id: runId }) 
            });
            const dataJobs = await resJobs.json();

            // Look for a job that likely uploaded artifacts (usually named 'build' or is the successful one)
            const buildJob = dataJobs.jobs.find(j => j.name.toLowerCase().includes('build') || j.conclusion === 'success');

            if (!buildJob) {
                toast.remove();
                return alert("Could not identify the build job for this run.");
            }

            // 2. Fetch the logs for that specific job
            const resLogs = await fetch(CONFIG.funcUrl, { 
                method: 'POST', 
                headers: {'Content-Type': 'application/json'}, 
                body: apiBody({ action: 'fetch_job_logs', job_id: buildJob.id }) 
            });
            const dataLogs = await resLogs.json();
            const logs = dataLogs.logs || "";

            // 3. Extract the URL using Regex (looking for the specific pattern in your logs)
            // Pattern: Artifact download URL: https://github.com/...
            const urlMatch = logs.match(/Artifact download URL:\s*(https?:\/\/[^\s]+)/);

            if (urlMatch && urlMatch[1]) {
                toast.style.background = "var(--prod)";
                toast.innerText = "📥 Starting Download...";

                // Trigger the download in a new tab
                window.open(urlMatch[1], '_blank');

                setTimeout(() => toast.remove(), 2000);
            } else {
                toast.remove();
                alert("Artifact URL not found in logs. It may still be processing or expired.");
            }

        } catch (e) {
            toast.remove();
            console.error("Download Error:", e);
            alert("Failed to extract artifact URL: " + e.message);
        }
    }

