private fun startMonitoring() {
    if (isObserverRegistered) return

    val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
    if (prefs.getLong("last_image_id", -1L) == -1L) {
        val projection = arrayOf(MediaStore.Images.Media._ID)
        contentResolver.query(MediaStore.Images.Media.EXTERNAL_CONTENT_URI, projection, null, null, "${MediaStore.Images.Media._ID} DESC LIMIT 1")?.use { cursor ->
