private fun prepareWideLens() {
    val root = rootInActiveWindow
    if (root == null) {
        DebugLogger.log("WIDE", "Root is null - UI not ready")
        return
    }

    DebugLogger.log("WIDE", "Searching for .5 button...")
    val queue = java.util.LinkedList<android.view.accessibility.AccessibilityNodeInfo>()
    queue.add(root)
    var wideNode: android.view.accessibility.AccessibilityNodeInfo? = null
    var nodesScanned = 0

    while (!queue.isEmpty()) {
        val node = queue.poll() ?: continue
        nodesScanned++
        val text = node.text?.toString()?.lowercase() ?: ""
        val desc = node.contentDescription?.toString()?.lowercase() ?: ""

        if (text.contains(".5") || text.contains("0.5") || desc.contains("zoom out") || desc.contains("ultra wide")) {
            DebugLogger.log("WIDE", "Found Button: Text='$text' Desc='$desc' Clickable=${node.isClickable}")
            wideNode = node
            break
        }

        for (i in 0 until node.childCount) {
            node.getChild(i)?.let { queue.add(it) }
        }
    }

    DebugLogger.log("WIDE", "Scan finished. Nodes inspected: $nodesScanned")

    if (wideNode != null) {
        val success = wideNode.performAction(android.view.accessibility.AccessibilityNodeInfo.ACTION_CLICK)
        DebugLogger.log("WIDE", "Click attempt on .5 button: Success=$success")
        if (success) return
    }

    // Fallback to Pinch
    DebugLogger.log("WIDE", "Button not found or click failed. Falling back to Pinch Gesture.")
    val metrics = resources.displayMetrics
    val centerX = metrics.widthPixels / 2f
    val centerY = metrics.heightPixels / 2f

    val path1 = android.graphics.Path().apply { moveTo(metrics.widthPixels * 0.2f, metrics.heightPixels * 0.3f); lineTo(centerX - 40, centerY - 40) }
    val path2 = android.graphics.Path().apply { moveTo(metrics.widthPixels * 0.8f, metrics.heightPixels * 0.7f); lineTo(centerX + 40, centerY + 40) }

    val gesture = android.accessibilityservice.GestureDescription.Builder()
        .addStroke(android.accessibilityservice.GestureDescription.StrokeDescription(path1, 0, 800))
        .addStroke(android.accessibilityservice.GestureDescription.StrokeDescription(path2, 0, 800)).build()

    dispatchGesture(gesture, object : AccessibilityService.GestureResultCallback() {
        override fun onCompleted(gd: android.accessibilityservice.GestureDescription) {
            DebugLogger.log("WIDE", "Fallback Pinch: SUCCESS")
        }
        override fun onCancelled(gd: android.accessibilityservice.GestureDescription) {
            DebugLogger.log("WIDE", "Fallback Pinch: CANCELLED (Check for system overlays)")
        }
    }, null)
}

